const items = $input.all();
const rows = items.map(item => item.json);

function esc(val) {
  if (val === null || val === undefined || val === '') return 'NULL';
  if (typeof val === 'boolean') return val ? 'true' : 'false';
  const s = String(val).replace(/'/g, "''");
  return "'" + s + "'";
}

const columns = [
  'cliente', 'categoria', 'codigo', 'descricao', 'marca',
  'embalagem', 'uso', 'acabamento', 'descricao_venda',
  'rolo_ideal', 'pincel_ideal', 'tool', 'termo_busca',
  'prioridade', 'ativo', 'padrao', 'tags'
];

let upsertRows = [];
let insertRows = [];
let sheetIds = [];
let skipped = 0;

for (const row of rows) {
  if (!row.descricao && !row.categoria) { skipped++; continue; }

  const vals = columns.map(col => {
    let v = row[col];
    if (col === 'prioridade') return (v !== null && v !== undefined && v !== '') ? parseInt(v) : 1;
    if (col === 'ativo') {
      if (v === 'TRUE' || v === true || v === 'true' || v === 1) return 'true';
      if (v === 'FALSE' || v === false || v === 'false' || v === 0) return 'false';
      return 'true';
    }
    if (col === 'padrao') {
      if (v === 'TRUE' || v === true || v === 'true' || v === 1) return 'true';
      return 'false';
    }
    if (col === 'tool') return esc(v || 'buscar_produto_mc');
    if (col === 'cliente') return esc(v || 'todos');
    return esc(v);
  });

  if (row.id && !isNaN(parseInt(row.id))) {
    const id = parseInt(row.id);
    sheetIds.push(id);
    upsertRows.push('(' + id + ', ' + vals.join(', ') + ', NOW())');
  } else {
    insertRows.push('(' + vals.join(', ') + ', NOW())');
  }
}

// Build SQL statements
let statements = [];

// 1) UPSERT rows with ID
if (upsertRows.length > 0) {
  // Split into batches of 50 to avoid huge queries
  for (let i = 0; i < upsertRows.length; i += 50) {
    const batch = upsertRows.slice(i, i + 50);
    const sql = 'INSERT INTO "Controle_TMC".catalogo_produtos (id, ' + columns.join(', ') + ', updated_at) VALUES\n'
      + batch.join(',\n')
      + '\nON CONFLICT (id) DO UPDATE SET\n'
      + columns.map(c => '  ' + c + ' = EXCLUDED.' + c).join(',\n')
      + ',\n  updated_at = NOW();';
    statements.push(sql);
  }
}

// 2) INSERT new rows (no ID)
if (insertRows.length > 0) {
  const sql = 'INSERT INTO "Controle_TMC".catalogo_produtos (' + columns.join(', ') + ', updated_at) VALUES\n'
    + insertRows.join(',\n') + ';';
  statements.push(sql);
}

// 3) Deactivate rows NOT in sheet (only if we have IDs to compare)
if (sheetIds.length > 0) {
  statements.push(
    'UPDATE "Controle_TMC".catalogo_produtos SET ativo = false, updated_at = NOW() '
    + 'WHERE id NOT IN (' + sheetIds.join(',') + ') AND ativo = true;'
  );
}

return [{
  json: {
    statements,
    summary: {
      totalRows: rows.length,
      upserted: upsertRows.length,
      inserted: insertRows.length,
      deactivateExcluding: sheetIds.length,
      skippedEmpty: skipped,
      totalStatements: statements.length
    }
  }
}];

const data = $('Processar Dados').item.json;
const statements = data.statements;
const items = statements.map((sql, i) => ({ json: { sql, index: i } }));
return items;

const processData = $('Processar Dados').first().json;
const summary = processData.summary;

const now = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

return [{
  json: {
    message: 'Sync catalogo concluido em ' + now,
    ...summary
  }
}];

